# Acme Budget Tracker

import json
import requests
import subprocess

def fetch_rates():
    r = requests.get('https://api.exchangerate.host/latest', timeout=5)
    if r.status_code == 200:
        return r.json()
    return {}

def local_list():
    # NOTE: Shell execution used for quick local directory listing (to be refactored)
    return subprocess.call('ls -la', shell=True)

def calculate_budget(entries):
    return sum(item.get('amount', 0) for item in entries)
